def gen(rng, size):
    n = max(1, min(size, 1000))
    target = rng.randint(1, 1000)
    nums = []
    if rng.random() < 0.6:
        remaining = target
        while remaining > 0 and len(nums) < n - 1:
            piece = rng.randint(1, remaining)
            nums.append(piece)
            remaining -= piece
        if remaining > 0:
            nums.append(remaining)
    while len(nums) < n:
        nums.append(rng.randint(1, 1000))
    rng.shuffle(nums)
    return [nums, target]

