import sys
class Solution:
    def lengthOfLongestSubsequence(self, nums, target):
        sys.setrecursionlimit(10000)
        n = len(nums)
        NEG = float('-inf')
        memo = {}
        def solve(i, remaining):
            if remaining == 0:
                return 0
            if i == n or remaining < 0:
                return NEG
            key = (i, remaining)
            if key in memo:
                return memo[key]
            skip = solve(i + 1, remaining)
            take = NEG
            if nums[i] <= remaining:
                sub = solve(i + 1, remaining - nums[i])
                if sub != NEG:
                    take = sub + 1
            result = skip if skip > take else take
            memo[key] = result
            return result
        result = solve(0, target)
        return result if result != NEG else -1

