class Solution:
    def lengthOfLongestSubsequence(self, nums, target):
        NEG = float('-inf')
        dp = [NEG] * (target + 1)
        dp[0] = 0
        for num in nums:
            if num > target:
                continue
            for s in range(target, num - 1, -1):
                if dp[s - num] != NEG and dp[s - num] + 1 > dp[s]:
                    dp[s] = dp[s - num] + 1
        return dp[target] if dp[target] != NEG else -1

